    block_number: u64,
    tx_hash: B256,
    precompile_address: Address,
    precompile_input: &Bytes,
    output: &Bytes,
    previous_block_hash: B256,
    previous_block_number: u64,
    previous_block_timestamp: u64,
    error: &str,
