    let mut ordered_map = BTreeMap::new();

    ordered_map
        .insert("block_number", serde_json::Value::Number(serde_json::Number::from(block_number)));
    ordered_map.insert("error", serde_json::Value::String(error.to_string()));
    ordered_map.insert("input", serde_json::Value::String(hex::encode(precompile_input)));
